import 'package:flutter/material.dart';\nimport 'package:flutter_riverpod/flutter_riverpod.dart';\nimport 'sell_provider.dart';\n\n/// Property Status Screen\n/// Track property verification status and admin review progress\nclass SellStatusScreen extends ConsumerStatefulWidget {\n  final String? propertyId;\n\n  const SellStatusScreen({Key? key, this.propertyId}) : super(key: key);\n\n  @override\n  ConsumerState<SellStatusScreen> createState() => _SellStatusScreenState();\n}\n\nclass _SellStatusScreenState extends ConsumerState<SellStatusScreen> {\n  late String _propertyId;\n\n  @override\n  void initState() {\n    super.initState();\n    _propertyId = widget.propertyId ?? ref.read(propertyIdProvider) ?? '';\n  }\n\n  @override\n  Widget build(BuildContext context) {\n    final theme = Theme.of(context);\n    final statusAsync = ref.watch(propertyStatusProvider(_propertyId));\n\n    return Scaffold(\n      appBar: AppBar(\n        title: const Text('Property Status'),\n        elevation: 0,\n        centerTitle: true,\n      ),\n      body: statusAsync.when(\n        data: (status) {\n          if (status == null) {\n            return _buildErrorState(theme);\n          }\n          return SingleChildScrollView(\n            padding: const EdgeInsets.all(16.0),\n            child: Column(\n              crossAxisAlignment: CrossAxisAlignment.start,\n              children: [\n                _buildPropertyIdCard(theme),\n                const SizedBox(height: 24),\n\n                // Status badge\n                _buildStatusBadge(status, theme),\n                const SizedBox(height: 24),\n\n                // Progress timeline\n                _buildStatusTimeline(status, theme),\n                const SizedBox(height: 24),\n\n                // Admin notes (if any)\n                if (status.adminNotes != null)\n                  _buildAdminNotesCard(status, theme),\n                const SizedBox(height: 24),\n\n                // Rejection reason (if rejected)\n                if (status.status == 'rejected' &&\n                    status.rejectionReason != null)\n                  _buildRejectionReasonCard(status, theme),\n                const SizedBox(height: 24),\n\n                // Action buttons\n                _buildActionButtons(status, theme),\n              ],\n            ),\n          );\n        },\n        loading: () => Center(\n          child: Column(\n            mainAxisAlignment: MainAxisAlignment.center,\n            children: [\n              const CircularProgressIndicator(),\n              const SizedBox(height: 16),\n              Text(\n                'Loading property status...',\n                style: theme.textTheme.bodyMedium,\n              ),\n            ],\n          ),\n        ),\n        error: (error, stack) => _buildErrorState(theme),\n      ),\n    );\n  }\n\n  Widget _buildPropertyIdCard(ThemeData theme) {\n    return Container(\n      padding: const EdgeInsets.all(12),\n      decoration: BoxDecoration(\n        color: theme.colorScheme.primaryContainer.withOpacity(0.3),\n        borderRadius: BorderRadius.circular(8),\n        border: Border.all(\n          color: theme.colorScheme.primary.withOpacity(0.5),\n        ),\n      ),\n      child: Row(\n        mainAxisAlignment: MainAxisAlignment.spaceBetween,\n        children: [\n          Column(\n            crossAxisAlignment: CrossAxisAlignment.start,\n            children: [\n              Text(\n                'Property ID',\n                style: theme.textTheme.labelSmall?.copyWith(\n                  color: theme.colorScheme.outline,\n                ),\n              ),\n              const SizedBox(height: 4),\n              Text(\n                _propertyId,\n                style: theme.textTheme.titleMedium?.copyWith(\n                  fontWeight: FontWeight.w700,\n                  fontFamily: 'monospace',\n                ),\n              ),\n            ],\n          ),\n          IconButton(\n            icon: const Icon(Icons.copy),\n            onPressed: () {\n              // Copy to clipboard\n              ScaffoldMessenger.of(context).showSnackBar(\n                const SnackBar(content: Text('Property ID copied')),\n              );\n            },\n          ),\n        ],\n      ),\n    );\n  }\n\n  Widget _buildStatusBadge(PropertySubmissionStatus status, ThemeData theme) {\n    final statusMap = {\n      'submitted': (\n        label: 'Submitted',\n        color: Colors.blue,\n        icon: Icons.send,\n      ),\n      'under_verification': (\n        label: 'Under Verification',\n        color: Colors.orange,\n        icon: Icons.schedule,\n      ),\n      'verified': (\n        label: 'Verified',\n        color: Colors.green,\n        icon: Icons.check_circle,\n      ),\n      'live': (\n        label: 'Live',\n        color: Colors.green,\n        icon: Icons.visibility,\n      ),\n      'sold': (\n        label: 'Sold',\n        color: Colors.purple,\n        icon: Icons.done_all,\n      ),\n      'rejected': (\n        label: 'Rejected',\n        color: Colors.red,\n        icon: Icons.close_circle,\n      ),\n    };\n\n    final info = statusMap[status.status] ??\n        (\n          label: 'Unknown',\n          color: Colors.grey,\n          icon: Icons.help_outline,\n        );\n\n    return Container(\n      padding: const EdgeInsets.all(20),\n      decoration: BoxDecoration(\n        color: info.color.withOpacity(0.1),\n        borderRadius: BorderRadius.circular(12),\n        border: Border.all(\n          color: info.color.withOpacity(0.5),\n        ),\n      ),\n      child: Column(\n        children: [\n          Icon(\n            info.icon,\n            size: 48,\n            color: info.color,\n          ),\n          const SizedBox(height: 12),\n          Text(\n            info.label,\n            style: theme.textTheme.headlineSmall?.copyWith(\n              color: info.color,\n              fontWeight: FontWeight.w700,\n            ),\n          ),\n          if (status.lastUpdatedAt != null)\n            Padding(\n              padding: const EdgeInsets.only(top: 8),\n              child: Text(\n                'Updated: ${_formatDate(status.lastUpdatedAt!)}',\n                style: theme.textTheme.labelSmall?.copyWith(\n                  color: theme.colorScheme.outline,\n                ),\n              ),\n            ),\n        ],\n      ),\n    );\n  }\n\n  Widget _buildStatusTimeline(PropertySubmissionStatus status, ThemeData theme) {\n    return Column(\n      crossAxisAlignment: CrossAxisAlignment.start,\n      children: [\n        Text(\n          'Progress Timeline',\n          style: theme.textTheme.titleMedium?.copyWith(\n            fontWeight: FontWeight.w600,\n          ),\n        ),\n        const SizedBox(height: 16),\n        ClipRRect(\n          borderRadius: BorderRadius.circular(4),\n          child: LinearProgressIndicator(\n            value: status.progressPercentage / 100,\n            minHeight: 8,\n            backgroundColor: theme.colorScheme.outline.withOpacity(0.2),\n            valueColor: AlwaysStoppedAnimation<Color>(\n              theme.colorScheme.primary,\n            ),\n          ),\n        ),\n        const SizedBox(height: 8),\n        Row(\n          mainAxisAlignment: MainAxisAlignment.spaceBetween,\n          children: [\n            Text(\n              'Progress',\n              style: theme.textTheme.labelSmall,\n            ),\n            Text(\n              '${status.progressPercentage}%',\n              style: theme.textTheme.labelSmall?.copyWith(\n                fontWeight: FontWeight.w600,\n              ),\n            ),\n          ],\n        ),\n        const SizedBox(height: 24),\n        // Timeline steps\n        _buildTimelineStep(\n          'Step 1',\n          'Property Submitted',\n          true,\n          theme,\n        ),\n        _buildTimelineStep(\n          'Step 2',\n          'Documents Verified',\n          status.progressPercentage >= 30,\n          theme,\n        ),\n        _buildTimelineStep(\n          'Step 3',\n          'Images Approved',\n          status.progressPercentage >= 60,\n          theme,\n        ),\n        _buildTimelineStep(\n          'Step 4',\n          'Final Review',\n          status.progressPercentage >= 80,\n          theme,\n        ),\n        _buildTimelineStep(\n          'Step 5',\n          'Published',\n          status.progressPercentage >= 100,\n          theme,\n        ),\n      ],\n    );\n  }\n\n  Widget _buildTimelineStep(\n    String stepLabel,\n    String description,\n    bool isCompleted,\n    ThemeData theme,\n  ) {\n    return Padding(\n      padding: const EdgeInsets.only(bottom: 12),\n      child: Row(\n        children: [\n          Container(\n            width: 32,\n            height: 32,\n            decoration: BoxDecoration(\n              shape: BoxShape.circle,\n              color: isCompleted\n                  ? Colors.green.shade600\n                  : theme.colorScheme.outline.withOpacity(0.2),\n            ),\n            child: Icon(\n              isCompleted ? Icons.check : Icons.schedule,\n              size: 16,\n              color: isCompleted ? Colors.white : theme.colorScheme.outline,\n            ),\n          ),\n          const SizedBox(width: 12),\n          Column(\n            crossAxisAlignment: CrossAxisAlignment.start,\n            children: [\n              Text(\n                stepLabel,\n                style: theme.textTheme.labelSmall?.copyWith(\n                  fontWeight: FontWeight.w600,\n                ),\n              ),\n              Text(\n                description,\n                style: theme.textTheme.labelSmall?.copyWith(\n                  color: theme.colorScheme.outline,\n                ),\n              ),\n            ],\n          ),\n        ],\n      ),\n    );\n  }\n\n  Widget _buildAdminNotesCard(PropertySubmissionStatus status, ThemeData theme) {\n    return Container(\n      padding: const EdgeInsets.all(12),\n      decoration: BoxDecoration(\n        color: Colors.blue.shade50,\n        borderRadius: BorderRadius.circular(8),\n        border: Border.all(color: Colors.blue.shade200),\n      ),\n      child: Column(\n        crossAxisAlignment: CrossAxisAlignment.start,\n        children: [\n          Row(\n            children: [\n              Icon(\n                Icons.info,\n                color: Colors.blue.shade600,\n                size: 20,\n              ),\n              const SizedBox(width: 8),\n              Text(\n                'Admin Notes',\n                style: theme.textTheme.labelMedium?.copyWith(\n                  fontWeight: FontWeight.w600,\n                  color: Colors.blue.shade700,\n                ),\n              ),\n            ],\n          ),\n          const SizedBox(height: 8),\n          Text(\n            status.adminNotes ?? '',\n            style: theme.textTheme.bodySmall?.copyWith(\n              color: Colors.blue.shade700,\n            ),\n          ),\n        ],\n      ),\n    );\n  }\n\n  Widget _buildRejectionReasonCard(PropertySubmissionStatus status, ThemeData theme) {\n    return Container(\n      padding: const EdgeInsets.all(12),\n      decoration: BoxDecoration(\n        color: Colors.red.shade50,\n        borderRadius: BorderRadius.circular(8),\n        border: Border.all(color: Colors.red.shade200),\n      ),\n      child: Column(\n        crossAxisAlignment: CrossAxisAlignment.start,\n        children: [\n          Row(\n            children: [\n              Icon(\n                Icons.warning,\n                color: Colors.red.shade600,\n                size: 20,\n              ),\n              const SizedBox(width: 8),\n              Text(\n                'Rejection Reason',\n                style: theme.textTheme.labelMedium?.copyWith(\n                  fontWeight: FontWeight.w600,\n                  color: Colors.red.shade700,\n                ),\n              ),\n            ],\n          ),\n          const SizedBox(height: 8),\n          Text(\n            status.rejectionReason ?? '',\n            style: theme.textTheme.bodySmall?.copyWith(\n              color: Colors.red.shade700,\n            ),\n          ),\n        ],\n      ),\n    );\n  }\n\n  Widget _buildActionButtons(PropertySubmissionStatus status, ThemeData theme) {\n    return Column(\n      children: [\n        SizedBox(\n          width: double.infinity,\n          child: FilledButton.icon(\n            onPressed: () {\n              ScaffoldMessenger.of(context).showSnackBar(\n                const SnackBar(content: Text('Listing shared')),\n              );\n            },\n            icon: const Icon(Icons.share),\n            label: const Text('Share Listing'),\n            style: FilledButton.styleFrom(\n              padding: const EdgeInsets.symmetric(vertical: 12),\n            ),\n          ),\n        ),\n        const SizedBox(height: 12),\n        SizedBox(\n          width: double.infinity,\n          child: OutlinedButton.icon(\n            onPressed: () {\n              ScaffoldMessenger.of(context).showSnackBar(\n                const SnackBar(content: Text('Opening listing...')),\n              );\n            },\n            icon: const Icon(Icons.open_in_new),\n            label: const Text('View Listing'),\n            style: OutlinedButton.styleFrom(\n              padding: const EdgeInsets.symmetric(vertical: 12),\n            ),\n          ),\n        ),\n        const SizedBox(height: 12),\n        SizedBox(\n          width: double.infinity,\n          child: OutlinedButton.icon(\n            onPressed: () {\n              ScaffoldMessenger.of(context).showSnackBar(\n                const SnackBar(content: Text('Contacting support...')),\n              );\n            },\n            icon: const Icon(Icons.contact_support),\n            label: const Text('Contact Support'),\n            style: OutlinedButton.styleFrom(\n              padding: const EdgeInsets.symmetric(vertical: 12),\n            ),\n          ),\n        ),\n      ],\n    );\n  }\n\n  Widget _buildErrorState(ThemeData theme) {\n    return Center(\n      child: Column(\n        mainAxisAlignment: MainAxisAlignment.center,\n        children: [\n          Icon(\n            Icons.error_outline,\n            size: 64,\n            color: Colors.red.shade600,\n          ),\n          const SizedBox(height: 16),\n          Text(\n            'Unable to load property status',\n            style: theme.textTheme.titleMedium,\n          ),\n          const SizedBox(height: 8),\n          Text(\n            'Please check the property ID and try again',\n            style: theme.textTheme.bodySmall?.copyWith(\n              color: theme.colorScheme.outline,\n            ),\n          ),\n          const SizedBox(height: 24),\n          FilledButton.tonal(\n            onPressed: () => setState(() {}),\n            child: const Text('Retry'),\n          ),\n        ],\n      ),\n    );\n  }\n\n  String _formatDate(DateTime date) {\n    return '${date.day}/${date.month}/${date.year}';\n  }\n}\n